# scripts/compute-quality-score.py
def score_metric(value: float, healthy: float, amber: float,
                 higher_is_better: bool = True) -> float:
    if higher_is_better:
        if value >= healthy: return 100.0
        if value >= amber:
            return 70.0 + 30.0 * (value - amber) / (healthy - amber)
        return max(0.0, 70.0 * value / amber)
    else:
        if value <= healthy: return 100.0
        if value <= amber:
            return 70.0 + 30.0 * (amber - value) / (amber - healthy)
        return max(0.0, 70.0 * (1.0 - (value - amber) / amber))

def compute_quality_score(metrics: dict) -> dict:
    scores = {
        "eval_pass_rate":         score_metric(metrics["eval_pass_rate"], 0.92, 0.85),
        "regression_delta":       score_metric(metrics["regression_delta"], 0.02, 0.05, higher_is_better=False),
        "injection_pass_rate":    score_metric(metrics["injection_pass_rate"], 1.0, 0.99),
        "eval_coverage":          score_metric(metrics["eval_coverage_per_capability"], 5, 2),
        "flaky_rate":             score_metric(metrics["flaky_rate"], 0.05, 0.10, higher_is_better=False),
        "dataset_staleness_days": score_metric(metrics["dataset_staleness_days"], 90, 180, higher_is_better=False),
    }
    overall = sum(scores.values()) / len(scores)

    # Injection is binary for status: any probe failure = Red regardless of score
    if metrics["injection_pass_rate"] < 1.0:
        status = "RED"
    elif overall >= 85:
        status = "GREEN"
    elif overall >= 70:
        status = "AMBER"
    else:
        status = "RED"

    return {"quality_score": round(overall, 1), "status": status, "metric_scores": scores}

# scripts/compute-reliability-score.py
def compute_reliability_score(metrics: dict) -> dict:
    scores = {
        "availability":         score_metric(metrics["availability_30d"], 99.5, 99.0),
        "p95_latency_pct":      score_metric(metrics["p95_latency_pct_of_sla"], 70, 90, higher_is_better=False),
        "error_rate":           score_metric(metrics["error_rate_pct"], 1.0, 3.0, higher_is_better=False),
        "truncation_rate":      score_metric(metrics["max_tokens_truncation_pct"], 5.0, 10.0, higher_is_better=False),
        "rollback_rate":        score_metric(metrics["rollback_rate_pct"], 2.0, 5.0, higher_is_better=False),
        "mttr_hours":           score_metric(metrics["mttr_hours"], 1.0, 4.0, higher_is_better=False),
    }
    overall = sum(scores.values()) / len(scores)

    if overall >= 85:
        status = "GREEN"
    elif overall >= 70:
        status = "AMBER"
    else:
        status = "RED"

    return {"reliability_score": round(overall, 1), "status": status, "metric_scores": scores}
